/* ====================== STORAGE (swappable) ================== */
// store importado de ./store.js (Supabase)
/* Chaves escopadas por conclave — um mestre pode ter várias mesas sem misturar */
const K = {
  meta: (c) => `cz:meta:${c}`,
  resp: (c, id) => `cz:resp:${c}:${id}`,
  respPrefix: (c) => `cz:resp:${c}:`,
};
const ALFA = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"; // sem I, O, 0, 1 (ambíguos)
async function gerarCodigo() {
  for (let t = 0; t < 25; t++) {
    const c = Array.from({ length: 4 }, () => ALFA[Math.floor(Math.random() * ALFA.length)]).join("");
    if (!(await store.get(K.meta(c)))) return c;
  }
  return Math.random().toString(36).slice(2, 6).toUpperCase();
}
async function criarConclave({ nome, senha }) {
  const codigo = await gerarCodigo();
  const meta = { codigo, nome: (nome || "").trim() || "Conclave sem nome", senha: (senha || "").trim() || "mestre", criadoEm: Date.now() };
  await store.set(K.meta(codigo), JSON.stringify(meta));
  return meta;
}
async function getConclave(codigo) {
  const raw = await store.get(K.meta((codigo || "").toUpperCase().trim()));
  return raw ? JSON.parse(raw) : null;
}

