async function semearDemo() {
  const codigo = "DEMO";
  await store.set(K.meta(codigo), JSON.stringify({ codigo, nome: "A Sociedade do Salão", senha: "mestre", criadoEm: Date.now() }));
  for (const base of DEMO) {
    const rank = [...AXES].sort((a, b) => base.scores[b] - base.scores[a]);
    const payload = {
      id: "demo_" + Math.random().toString(36).slice(2, 7),
      nome: base.nome, criadoEm: Date.now() + Math.floor(Math.random() * 1000),
      experiencia: base.experiencia, posicao: base.posicao,
      sistemas: base.sistemas || [], procura: base.procura || [], tipoCampanha: base.tipoCampanha || "",
      scores: base.scores, dominante: rank[0], secundario: rank[1],
      redFlags: base.redFlags, tom: base.tom,
      linhas: base.linhas || "", veus: base.veus || "", expectativas: base.expectativas || "",
    };
    await store.set(K.resp(codigo, payload.id), JSON.stringify(payload));
  }
  return { codigo, nome: "A Sociedade do Salão", senha: "mestre" };
}

/* ======================= UTILIDADES UI ======================= */
function Sigil({ data, cor = T.gold, size = 240 }) {
  // radar estilizado como brasão
  return (
    <div style={{ width: "100%", height: size }}>
      <ResponsiveContainer>
        <RadarChart data={data} outerRadius="72%">
          <PolarGrid stroke={T.line} />
          <PolarAngleAxis dataKey="eixo" tick={{ fill: T.ink2, fontSize: 11, fontFamily: display }} />
          <PolarRadiusAxis domain={[0, 100]} tick={false} axisLine={false} />
          <Radar dataKey="valor" stroke={cor} strokeWidth={2} fill={cor} fillOpacity={0.32} />
        </RadarChart>
      </ResponsiveContainer>
    </div>
  );
}

function Btn({ children, onClick, variant = "ghost", disabled, style, full }) {
  const base = {
    fontFamily: display, fontSize: 14, letterSpacing: ".05em", cursor: disabled ? "not-allowed" : "pointer",
    padding: "12px 20px", borderRadius: 4, transition: "all .15s", display: "inline-flex",
    alignItems: "center", justifyContent: "center", gap: 8, width: full ? "100%" : "auto",
    opacity: disabled ? 0.4 : 1, textTransform: "uppercase",
  };
  const variants = {
    solid: { background: `linear-gradient(180deg, ${T.gold}, #a8861f)`, color: "#1a1207", border: "1px solid " + T.goldSoft, fontWeight: 600 },
    ghost: { background: "transparent", color: T.ink2, border: "1px solid " + T.line },
    blood: { background: "transparent", color: T.ember, border: "1px solid rgba(168,50,50,.4)" },
  };
  return (
    <button onClick={disabled ? undefined : onClick} disabled={disabled}
      style={{ ...base, ...variants[variant], ...style }}>{children}</button>
  );
}

/* =========================== APP ============================= */
function Particles() {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const reduced = typeof window.matchMedia === "function" && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    const COLORS = ["#cda434", "#e0c66a", "#e07b39"];
    let w = 0, h = 0, parts = [], raf = 0;
    const N = reduced ? 0 : 44;
    const mk = () => ({
      x: Math.random() * w, y: Math.random() * h,
      r: Math.random() * 1.8 + 0.6,
      vy: -(Math.random() * 0.35 + 0.12),
      sway: Math.random() * 0.5 + 0.2,
      phase: Math.random() * Math.PI * 2,
      tw: Math.random() * 0.018 + 0.004,
      base: Math.random() * 0.35 + 0.25,
      color: COLORS[(Math.random() * COLORS.length) | 0],
    });
    const resize = () => {
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      w = window.innerWidth; h = window.innerHeight;
      canvas.width = w * dpr; canvas.height = h * dpr;
      canvas.style.width = w + "px"; canvas.style.height = h + "px";
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      parts = Array.from({ length: N }, mk);
    };
    const frame = () => {
      ctx.clearRect(0, 0, w, h);
      for (const p of parts) {
        p.y += p.vy; p.phase += p.tw;
        p.x += Math.sin(p.phase) * p.sway * 0.3;
        if (p.y < -12) { p.y = h + 12; p.x = Math.random() * w; }
        const op = Math.max(0, p.base + Math.sin(p.phase) * 0.3);
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = p.color; ctx.globalAlpha = op;
        ctx.shadowBlur = 8; ctx.shadowColor = p.color;
        ctx.fill();
      }
      ctx.globalAlpha = 1; ctx.shadowBlur = 0;
      raf = requestAnimationFrame(frame);
    };
    resize();
    if (!reduced) raf = requestAnimationFrame(frame);
    window.addEventListener("resize", resize);
    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", resize); };
  }, []);
  return <canvas ref={ref} aria-hidden="true" style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0 }} />;
}

